const allOf = function (name) { try { const items = $(name).all().map(function (i) { return i.json; }); if (items.length === 1 && Array.isArray(items[0])) return items[0]; return items; } catch (e) { return []; } };
const rules  = allOf('Fetch Rules');
const events = allOf('Fetch Events');

const nowHour = new Date().toISOString().slice(0, 13);
const alerts = [];

rules.forEach(function (rule) {
  const windowStart = Date.now() - (rule.window_minutes * 60 * 1000);
  // Filter events: match event_type_filter + within window.
  const matching = events.filter(function (e) {
    if (rule.event_type_filter && e.event_type !== rule.event_type_filter) return false;
    const t = new Date(e.created_at).getTime();
    return t >= windowStart;
  });
  // Group by the rule's grouping key.
  const counts = {};
  matching.forEach(function (e) {
    const key = e[rule.group_by] || '_null';
    if (!counts[key]) counts[key] = { count: 0, sample_user_email: e.user_email, sample_source_ip: e.source_ip, sample_endpoint: e.endpoint, latest_event_at: e.created_at };
    counts[key].count += 1;
    if (e.created_at > counts[key].latest_event_at) counts[key].latest_event_at = e.created_at;
  });
  // Raise an alert for any group that hit the threshold.
  Object.keys(counts).forEach(function (key) {
    const c = counts[key];
    if (c.count < rule.threshold_count) return;
    if (key === '_null') return;  // skip ungrouped
    alerts.push({
      severity:    rule.severity,
      alert_type:  'security_' + rule.rule_type,
      title:       '[' + rule.rule_name + '] ' + c.count + ' events for ' + rule.group_by + '=' + key + ' in ' + rule.window_minutes + 'min',
      message:     rule.description + '. Latest event ' + c.latest_event_at + '.',
      aggregation_key: 'security:' + rule.rule_name + ':' + key + ':' + nowHour,
      details:     { rule_name: rule.rule_name, rule_type: rule.rule_type, group_by: rule.group_by, group_value: key, event_count: c.count, window_minutes: rule.window_minutes, threshold: rule.threshold_count, sample_endpoint: c.sample_endpoint, latest_event_at: c.latest_event_at }
    });
  });
});

return { json: { alerts: alerts, rules_evaluated: rules.length, events_considered: events.length } };

const alerts = $input.item.json.alerts || [];
if (!alerts.length) return [{ json: { _no_alerts: true } }];
return alerts.map(function (a) { return { json: a }; });
